11	export function truncateHash(hash: string, len = 8): string {
12	  if (hash.startsWith("sha256:")) return `sha256:${hash.slice(7, 7 + len)}…`;
13	  return hash.length > len ? `${hash.slice(0, len)}…` : hash;
14	}
