    queryFn: () => api.getServiceIndex(),
    staleTime: 60000,  // 1 minute before refetch
  });
}

export function useMarkets(filters: MarketListFilters = {}) {
  return useQuery({
    queryKey: queryKeys.markets(filters),
    queryFn: () => api.listMarkets(filters),
    refetchInterval: 5000,  // 5 second polling
  });
}
```

**Query States Returned:**
- `data`: Actual response data
- `isLoading`: Initially loading
- `isError`: Query failed
- `error`: Error object
- `isPending`, `isSuccess`, `isFetching`, `isRefetching`: Other states

---

### **7. FORMAT UTILITY**
**File:** `/tmp/temporal-worktrees/task-task-system-coverage-001/frontend/src/lib/utils/format.ts` (47 lines)

**`formatCurrency()` Function:**
```typescript
export function formatCurrency(n: number): string {
  if (Math.abs(n) >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`;
  if (Math.abs(n) >= 1_000) return `${(n / 1_000).toFixed(1)}K`;
  return n.toFixed(2);
}
```
- Converts numbers to M/K format or 2 decimal places
- Used for volume and liquidity display

---

### **8. PRODUCTION PROVIDERS**
**File:** `/tmp/temporal-worktrees/task-task-system-coverage-001/frontend/src/app/providers.tsx` (26 lines)

**Production QueryClient:**
```typescript
const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      staleTime: 2000,   // 2 seconds before considered stale
      retry: 1,          // Retry failed queries once
    },
  },
});
```

**Difference from Test:** Production has `retry: 1` and `staleTime: 2000` vs test's `retry: false` and `gcTime: 0`.

---

### **9. INLINE STYLE ASSERTION PATTERNS**

Based on codebase analysis across multiple test files, here are the established patterns:

**Pattern 1: Direct `toHaveStyle()` with object**
```typescript
